import hmac, hashlib, time
from flask import request, abort
class WebhookVerifier:
    def __init__(self, secret, tolerance=300):
        self.secret = secret.encode()
        self.tolerance = tolerance
    def verify(self, payload, signature, timestamp=None):
        if timestamp and abs(time.time() - int(timestamp)) > self.tolerance:
            raise ValueError("Webhook too old")
        signed = f"{timestamp}.".encode() + payload if timestamp else payload
        expected = hmac.new(self.secret, signed, hashlib.sha256).hexdigest()
        sig_value = signature.split('=', 1)[-1] if '=' in signature else signature
        if not hmac.compare_digest(expected, sig_value):
            raise ValueError("Invalid signature")
        return True
    def middleware(self, f):
        def decorated(*a, **kw):
            try: self.verify(request.get_data(), request.headers.get('X-Webhook-Signature', ''), request.headers.get('X-Webhook-Timestamp', ''))
            except ValueError as e: abort(401, str(e))
            return f(*a, **kw)
        return decorated
